function LBattleViewSpineQueue:MakeObject(objData)
    local key = objData.key
    local objectData = self._objList[key]
    ---@type LxSpineDp
    local spine = nil
    if objectData then
        objectData.objData = objData
        if objectData.isLoaded then
            self:OnSpineLoaded(key)
        end
        spine = objectData.spine
    else

        spine = require("LApp.component.dp.LxSpineDp"):new()
        objectData = {spine = spine,objData = objData}
        self._objList[key] = objectData
        local trans = objData.trans
        local spineName = objData.resName
        --local spineType = objData.spineType or LDisplaySpine.TYPE_MODEL
        spine:InitDp(spineName, trans)
